import React, { useState } from 'react';
import { LayoutDashboard, FileSpreadsheet, Bot, Settings, Play, Download, AlertCircle, CheckCircle2, CalendarDays, ClipboardPaste, Loader2, Database, Building2, Cpu, CalendarClock, Plus, Trash2, Save } from 'lucide-react';

export default function App() {
  const [activeTab, setActiveTab] = useState('fcst');
  const [fcstInput, setFcstInput] = useState('');
  const [sompInput, setSompInput] = useState('');
  const [results, setResults] = useState([]);
  const [status, setStatus] = useState({ type: 'idle', message: '' });

  const [mappingRules, setMappingRules] = useState(() => {
    const saved = localStorage.getItem('pskMasterData');
    return saved ? JSON.parse(saved) : {
      lineMap: { 'T1': 'SEC-T1(USA)', 'P1F': 'SEC-P1(F)(KR)' },
      fabClientMap: { 'SEC-T1(USA)': 'Samsung Electronics' },
      modelMap: { 'SUPRA-N': { model: 'SUPRA N', pm: 0 } },
      atmMaster: [{ id: 'ATM-102', start: '2026-01-13', end: '2026-01-29', maxCapa: 6 }]
    };
  });

  const saveRules = (newRules) => { setMappingRules(newRules); localStorage.setItem('pskMasterData', JSON.stringify(newRules)); };

  // --- 기존의 processData 및 추가/삭제 로직들을 여기 그대로 유지하시면 됩니다 ---
  // (공간 관계상 핵심 구조만 표기했으니, 기존 코드를 이 함수들 내부에 넣어 완성하세요)
  const processData = () => { /* 여기에 기존 코드 붙여넣기 */ };
  const addAtmRule = () => { /* 여기에 기존 코드 붙여넣기 */ };
  const removeAtmRule = (id) => { saveRules({...mappingRules, atmMaster: mappingRules.atmMaster.filter(a => a.id !== id)}); };

  return (
    <div className="flex h-screen bg-gray-50 font-sans">
      <aside className="w-64 bg-[#1a233a] text-gray-300 shadow-xl z-20">
        <div className="h-16 flex items-center px-6 bg-[#111827] text-white font-bold"><Bot className="mr-2 text-blue-400"/> Team AI Portal</div>
        <nav className="p-4 space-y-2">
          <button onClick={() => setActiveTab('fcst')} className={`w-full flex items-center p-3 rounded ${activeTab === 'fcst' ? 'bg-blue-600 text-white' : 'hover:bg-gray-800'}`}><CalendarDays className="mr-2" size={18}/> FCST 스케줄러</button>
          <button onClick={() => setActiveTab('master')} className={`w-full flex items-center p-3 rounded ${activeTab === 'master' ? 'bg-blue-600 text-white' : 'hover:bg-gray-800'}`}><Database className="mr-2" size={18}/> 데이터 관리</button>
        </nav>
      </aside>

      <main className="flex-1 p-8 overflow-y-auto">
        {activeTab === 'fcst' ? (
          <div className="max-w-6xl space-y-6">
            <div className="grid grid-cols-2 gap-6">
              <div className="bg-white p-4 rounded-xl border shadow-sm"><h3 className="font-bold mb-2">STEP 1. 신규 FCST</h3><textarea className="w-full h-48 bg-gray-50 border-0 p-2 text-xs" onChange={e => setFcstInput(e.target.value)} value={fcstInput}/></div>
              <div className="bg-white p-4 rounded-xl border shadow-sm"><h3 className="font-bold mb-2">STEP 2. 기존 SOMP</h3><textarea className="w-full h-48 bg-gray-50 border-0 p-2 text-xs" onChange={e => setSompInput(e.target.value)} value={sompInput}/></div>
            </div>
            <button onClick={processData} className="bg-blue-600 text-white px-8 py-3 rounded-lg font-bold">자동 배정 시작</button>
          </div>
        ) : (
          <div className="max-w-6xl bg-white p-6 rounded-xl border shadow-sm">
            <h2 className="text-xl font-bold mb-6">ATM 가동 스케줄 에디터</h2>
            <table className="w-full text-left border">
              <thead className="bg-gray-50"><tr><th className="p-3 border">ID</th><th className="p-3 border">시작일</th><th className="p-3 border">종료일</th><th className="p-3 border">Capa</th><th className="p-3 border">삭제</th></tr></thead>
              <tbody>
                {mappingRules.atmMaster.map(atm => (
                  <tr key={atm.id}>
                    <td className="p-3 border">{atm.id}</td><td className="p-3 border">{atm.start}</td><td className="p-3 border">{atm.end}</td><td className="p-3 border">{atm.maxCapa}</td>
                    <td className="p-3 border"><button onClick={() => removeAtmRule(atm.id)} className="text-red-500"><Trash2 size={18}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}
